create table dirkspzm32.lvs_lam_hist (
    sid                      varchar2(2 char) not null enable,
    firma_nr                 number(2, 0) not null enable,
    lam_id                   number(*, 0) not null enable,
    artikel_id               number(*, 0),
    lgr_platz                varchar2(30 char),
    lte_id                   varchar2(20 char),
    lhm_id                   varchar2(20 char),
    charge_id                number(*, 0),
    serie_id                 number(*, 0),
    leitzahl                 number(*, 5),
    fa_ag                    number(*, 5),
    fa_upos                  number(*, 5),
    abnr                     varchar2(20 char),
    best_nr                  varchar2(20 char),
    best_pos                 varchar2(5 char),
    res_id                   number(*, 0),
    prod_datum               date,
    zug_datum                date,
    ls_login_id              number(*, 0),
    menge                    number(*, 3),
    lam_kg                   number(*, 6),
    lam_text                 varchar2(40 char),
    labor_status             varchar2(1 char),
    labor_text               varchar2(30 char),
    lam_mhd                  date,
    kunden_nr                varchar2(20 char),
    kd_art_nr                varchar2(30 char),
    lieferant_nr             varchar2(20 char),
    lam_mhd_ausgabe          date,
    menge_basis              varchar2(3 char) not null enable,
    mengeneinheit_basis      varchar2(10 char) not null enable,
    order_pos_auf_id         number(*, 0),
    zeichnung                varchar2(255 char),
    zeichnung_index          varchar2(10 char),
    li_nr_lief               varchar2(20 char),
    lte_id_lieferant         varchar2(20 char),
    sonst_id_lieferant       varchar2(20 char),
    akt_inventur_id          number(*, 0),
    letzte_inventur_id       number(*, 0),
    letzte_inventur_datum    date,
    letzte_inventur_login_id number(*, 0),
    lam_p1                   varchar2(30 char),
    lam_p2                   varchar2(30 char),
    lam_p3                   varchar2(30 char),
    lam_p4                   varchar2(30 char),
    lam_p5                   varchar2(30 char),
    lam_p6                   varchar2(30 char),
    lam_p7                   varchar2(30 char),
    lam_p8                   varchar2(30 char),
    lam_p9                   varchar2(30 char),
    lam_p10                  varchar2(30 char),
    res_menge                number(*, 3),
    res_ziel_lte_id          varchar2(20 char),
    res_login_id             number(*, 0),
    check_ware_transp_id     number(*, 0),
    fae_id                   varchar2(20 char),
    fae_id_position          varchar2(1 char),
    qs_status                varchar2(10 char),
    waren_typ                varchar2(3 char),
    lhm_lfd_nr               number(*, 5),
    packschema_kopf_id       varchar2(20 char),
    packschema_lfdn          number(*, 5),
    lhm_c_lfd_nr             number(*, 5),
    owner_address_id         number(*, 0),
    lam_sel1                 varchar2(30 char),
    lam_sel2                 varchar2(30 char),
    lam_sel3                 varchar2(30 char),
    lam_sel4                 varchar2(30 char),
    lam_sel5                 varchar2(30 char),
    lam_sel6                 varchar2(30 char),
    lam_sel7                 varchar2(30 char),
    lam_sel8                 varchar2(30 char),
    lam_sel9                 varchar2(30 char),
    lam_sel10                varchar2(30 char),
    hersteller_kuerzel_liste varchar2(100 char),
    nr_pruefung              varchar2(20 char)
);

alter table dirkspzm32.lvs_lam_hist
    add constraint pk_lvs_lam_hist
        primary key ( sid,
                      firma_nr,
                      lam_id )
            using index enable;


